function loadMath() {
	_$math = {
		random: function(x, y) {return Math.floor((Math.random() * y) + x) },
		seed: function(x) {
			var c = "";
			for(i=0; i < x; i++) {
				  c += (Math.floor((Math.random() * 9) + 1))
				}
				return c;
			},
		parityArray: function(x) {
			if( x.length % 2 >= 1 ) {
				return false;
			} if( x.length % 2 <= 0 ){
				return true;
			}
		},

		median: function(k) {
			var x = k.sort(function(a, b){return a-b});
			if( x.length % 2 >= 1 ) {
			 	var m = x.length / 2,
			 	i = Math.ceil(m) - 1;
				return x[i];
			}
			if( x.length % 2 <= 0 ){
				var m = x.length / 2,
				o = x.length / 2 + 1,
				t = x[m - 1] + x[o - 1];
				return t / 2;
			}
		},

		range: function(n) {
			var j = n.sort(function(a, b){return a-b});
			var i = j.length - 1;
			var k = j[i] - j[0];
			return k;
		},

		mean: function(z) {
			var v = 0;
			for(i=0; i < z.length; i++ ) {
				v += z[i];
			}
			var u = v / z.length;
			return u;
		},

		parity: function(x) {
			if( x % 2 >= 1 ) {
				return false;
			} if( x % 2 <= 0 ){
				return true;
			}
		},


	}
}
